const items = $input.all(); // 获取所有输入项

function getPPID(sn) {
    const snToPpidMap = {
        "W92": "828649-509327",
        "W51": "828649-833829",
        "W52": "828649-814264"
    };

    const prefix = sn.substring(0, 3); // 修改为提取前三个字符

    return snToPpidMap.hasOwnProperty(prefix) ? snToPpidMap[prefix] : "未找到对应的ppid";
}

const results = items.map(item => {
    const sn = item.json.body.sn; // 从每个项中提取序列号
    const ppid = getPPID(sn);

    return {
        json: {
            sn: sn,
            ppid: ppid
        }
    };
});

return results;

const items = $input.all(); // 获取所有输入项

// 假设数据在第一个输入项目的 "data" 字段中
const rawData = items[0].json.data;

// 将字符串数据以 CRLF 分割成数组
const lines = rawData.trim().split('\r\n');

// 初始化 auth_entities 数组
const authEntities = [];

// 解析每行并生成目标数据结构
lines.forEach(line => {
    const [, tokenId, base64Token] = line.split(',', 3); // 提取 tokenId 和 Base64-encoded Token
    authEntities.push({ tokenId, "Base64-encoded Token": base64Token });
});

// 组装最终结果
const result = {
    ppid: lines.length > 0 ? lines[0].split(',')[0] : null,  // 假设所有行的 ppid 相同
    auth_entities: authEntities // auth_entities 是一个包含 tokenId 和 base64Token 对象的数组
};

// 返回结果
return {
    json: result
};
